import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { RouterLink } from '@angular/router';
import { AuthService } from '../../services/auth.service';
import { AiService } from '../../services/ai.service';

type ChatMessage = {
  role: 'user' | 'assistant';
  content: string;
};

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule, RouterLink],
  templateUrl: './dashboard.html',
  styleUrls: ['./dashboard.css']
})
export class DashboardComponent implements OnInit {
  userEmail = '';
  userName = '';
  message = '';
  isLoading = false;
  errorMessage = '';
  chat: ChatMessage[] = [];

  constructor(private authService: AuthService, private aiService: AiService) {}

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (profile) => {
        this.userEmail = profile.email;
        this.userName = profile.firstName || profile.email;
        this.chat.push({
          role: 'assistant',
          content: 'Describe your symptoms. I will ask yes/no questions to narrow it down.'
        });
      },
      error: () => {
        this.errorMessage = 'Please log in again to start the medical assistant.';
      }
    });
  }

  sendMessage(): void {
    const trimmed = this.message.trim();
    if (!trimmed || !this.userEmail || this.isLoading) {
      return;
    }

    this.chat.push({ role: 'user', content: trimmed });
    this.message = '';
    this.isLoading = true;
    this.errorMessage = '';

    this.aiService.chat(this.userEmail, trimmed).subscribe({
      next: (response) => {
        this.chat.push({ role: 'assistant', content: response.reply });
        this.isLoading = false;
      },
      error: () => {
        this.errorMessage = 'The medical AI is unavailable right now.';
        this.isLoading = false;
      }
    });
  }

  resetChat(): void {
    if (!this.userEmail) {
      return;
    }

    this.aiService.reset(this.userEmail).subscribe({
      next: () => {
        this.chat = [
          {
            role: 'assistant',
            content: 'Chat reset. Describe your symptoms again.'
          }
        ];
      }
    });
  }
}
